module d_flip_flop(
    input clk,          // Clock signal.
    input rst_n,        // Active-low synchronous reset.
    input d,            // Data input.
    output reg q        // Data output.
);

// Flip-Flop logic
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (!rst_n) begin
        q <= 0;
    end else begin
        q <= d;
    end
end

endmodule
